  ('pukao-7c4986e7-moex-00032', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-114-6948958a', 'sub-pukao-7c4986e7-03', NULL, 'single_choice', '若一企業對一商品採取「薄利多銷」的銷售策略，此策略要能成功，則必須該財貨的：', '["供給彈性小", "供給彈性大", "需求彈性小", "需求彈性大"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:44+00:00", "source_pdf_sha1": "7f60f8d3aafd", "answer_pdf_sha1": "79d6a424ea53", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "414", "s": "0709", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL),
